import React, { useEffect, useState } from "react";

const [medicines, setMedicines] = useState([]);
const [search, setSearch] = useState("");

const fetchMedicines = () => {
  fetch(`http://127.0.0.1:8000/inventory?search=${search}`)
    .then((res) => res.json())
    .then((data) => setMedicines(data.data));
};

useEffect(() => {
  fetchMedicines();
}, []);

function App() {
  const [medicines, setMedicines] = useState([]);

  useEffect(() => {
    fetch("http://127.0.0.1:8000/inventory")
      .then((res) => res.json())
      .then((data) => {
        setMedicines(data.data); // because API returns {data: []}
      });
  }, []);

  return (
    <div style={{ padding: "40px" }}>
      <h1>Pharmacy Inventory</h1>

      <input
        type="text"
        placeholder="Search medicine..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <button onClick={fetchMedicines}>Search</button>

      <table border="1" cellPadding="10">
        <thead>
          <tr>
            <th>Name</th>
            <th>Quantity</th>
            <th>Status</th>
            <th>Price</th>
          </tr>
        </thead>

        <tbody>
          {medicines.map((med) => (
            <tr key={med.id}>
              <td>{med.name}</td>
              <td>{med.quantity}</td>
              <td>{med.status}</td>
              <td>{med.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
